// ============================================
// KONFIGURACJA SYSTEMU
// ============================================
const CONFIG = {
  clickup: {
    token: 'pk_284536279_ARCLCZPXOG0PMONQ5IBNKY5UJDI4HJRE',
    spaceId: '90152423592',
    lists: {
      hostessyDzisiaj: '901522609104',
      hostessyRaporty: '901522609109',
      alertyAktywne:   '901522609082',
      raportyCodzienne:'901522609089'
    },
    fields: {
      stanKoncowy:      'eb918b95-6861-4fe9-bdcf-d325b866042a',
      dzienZamkniety:   'e87201aa-9a63-4316-bad0-5d10fc542b9c',
      liczbaSpoznien:   'fd00d8d9-6e60-49fb-a489-e0f4901512b2',
      // PODMIEŃ PO DOSTANIU IDS:
      godzinaPrzyjscia: 'PLACEHOLDER_GODZINA_PRZYJSCIA',
      czyZarej:         'PLACEHOLDER_CZY_ZAREJESTROWANA',
      stanPoczatkowy:   'PLACEHOLDER_STAN_POCZATKOWY',
      stan1300:         'PLACEHOLDER_STAN_1300',
      rozdanoLacznie:   'PLACEHOLDER_ROZDANO_LACZNIE',
      alertNiskiStan:   'PLACEHOLDER_ALERT_NISKI_STAN',
      raportPolowkowy:  'PLACEHOLDER_RAPORT_POLOWKOWY',
      raportPolOddany:  'PLACEHOLDER_RAPORT_POL_ODDANY',
      godzinaRapPol:    'PLACEHOLDER_GODZINA_RAP_POL',
      ocenaPolowyDnia:  'PLACEHOLDER_OCENA_POLOWY',
      raportKoncowy:    'PLACEHOLDER_RAPORT_KONCOWY',
      raportKonOddany:  'PLACEHOLDER_RAPORT_KON_ODDANY',
      godzinaWyjscia:   'PLACEHOLDER_GODZINA_WYJSCIA',
      etapAktualny:     'PLACEHOLDER_ETAP_AKTUALNY',
      flagaProblemu:    'PLACEHOLDER_FLAGA_PROBLEMU',
      email:            'PLACEHOLDER_EMAIL',
      telefon:          'PLACEHOLDER_TELEFON',
      nazwaZespolu:     'PLACEHOLDER_NAZWA_ZESPOLU',
      stanowisko:       'PLACEHOLDER_STANOWISKO',
      spoznienieMin:    'PLACEHOLDER_SPOZNIENIE_MIN',
      planowanaGodzina: 'PLACEHOLDER_PLANOWANA_GODZINA'
    }
  },
  godziny: {
    start: '08:00',
    koniec: '17:00',
    raportPolowkowy: '13:00',
    raportKoncowy: '17:00',
    progNiskiStan: 30,
    progSpoznienia: 15,
    progSpoznienZarzad: 3
  },
  emaile: {
    zarzad: 'autoleads@gmail.com',
    domyslny: 'testautoleads@gmail.com',
    system: 'testautoleads@gmail.com'
  },
  statusy: {
    oczekuje: 'OCZEKUJE',
    etap12: 'ETAP 1-2',
    etap34: 'ETAP 3-4',
    etap5: 'ETAP 5',
    etap6: 'ETAP 6',
    wymagaUwagi: 'WYMAGA UWAGI',
    zakonczona: 'ZAKOŃCZONA'
  }
};

// Pobierz dane z webhooka
const raw = $input.first().json;
const d = raw.body || raw;

// Walidacja
const errors = [];
if (!d.imie_nazwisko)   errors.push('Brak imienia i nazwiska');
if (!d.email)           errors.push('Brak emaila');
if (!d.stan_poczatkowy || isNaN(parseInt(d.stan_poczatkowy))) {
  errors.push('Brak lub nieprawidłowy stan początkowy');
}

if (errors.length > 0) {
  return [{ json: { ok: false, errors, CONFIG } }];
}

// Oblicz godzinę i spóźnienie
const now = new Date();
const hh = now.getHours().toString().padStart(2, '0');
const mm = now.getMinutes().toString().padStart(2, '0');
const godzina = d.godzina_przyjscia || (hh + ':' + mm);

const [hP, mP] = godzina.split(':').map(Number);
const [hS, mS] = CONFIG.godziny.start.split(':').map(Number);
const spoznMin = (hP * 60 + mP) - (hS * 60 + mS);
const czySpozn = spoznMin > CONFIG.godziny.progSpoznienia;

const dataStr = now.toLocaleDateString('pl-PL', {
  day: '2-digit', month: '2-digit', year: 'numeric'
});
const dataNazwa = now.toLocaleDateString('pl-PL', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

// Email pracownika lub domyślny testowy
const emailPracownik = d.email.includes('@') 
  ? d.email.trim().toLowerCase() 
  : CONFIG.emaile.domyslny;

return [{
  json: {
    ok: true,
    CONFIG,
    imie: d.imie_nazwisko.trim(),
    email: emailPracownik,
    telefon: d.telefon || '',
    stanowisko: d.stanowisko || 'Stanowisko główne',
    zespol: d.nazwa_zespolu || 'Hostessy',
    stanPoczatkowy: parseInt(d.stan_poczatkowy),
    czyZarej: d.czy_zarejestrowala === 'TAK' || d.czy_zarejestrowala === true,
    godzina,
    spoznMin: Math.max(0, spoznMin),
    czySpozn,
    dataStr,
    dataNazwa,
    listId: CONFIG.clickup.lists.hostessyDzisiaj,
    mgrEmail: CONFIG.emaile.domyslny,
    zarzadEmail: CONFIG.emaile.zarzad,
    sysEmail: CONFIG.emaile.system,
    timestamp: now.toISOString()
  }
}];

const dane = $('WALIDACJA - Dane i Config').item.json;
const task = $input.first().json;

if (!task.id) {
  throw new Error('ClickUp nie zwrócił ID taska. Odpowiedź: ' + JSON.stringify(task));
}

return [{
  json: {
    ...dane,
    taskId: task.id,
    taskUrl: task.url,
    taskName: task.name
  }
}];

const d = $input.first().json;
const C = d.CONFIG;

// Przygotuj aktualizacje custom fields
// Tylko te pola które mamy już z ID
const updates = [
  {
    fieldId: C.clickup.fields.stanPoczatkowy,
    value: d.stanPoczatkowy,
    name: 'Stan Początkowy'
  },
  {
    fieldId: C.clickup.fields.godzinaPrzyjscia,
    value: d.godzina,
    name: 'Godzina Przyjścia'
  },
  {
    fieldId: C.clickup.fields.email,
    value: d.email,
    name: 'Email'
  },
  {
    fieldId: C.clickup.fields.telefon,
    value: d.telefon,
    name: 'Telefon'
  },
  {
    fieldId: C.clickup.fields.stanowisko,
    value: d.stanowisko,
    name: 'Stanowisko'
  },
  {
    fieldId: C.clickup.fields.nazwaZespolu,
    value: d.zespol,
    name: 'Nazwa Zespołu'
  },
  {
    fieldId: C.clickup.fields.planowanaGodzina,
    value: C.godziny.start,
    name: 'Planowana Godzina'
  },
  {
    fieldId: C.clickup.fields.spoznienieMin,
    value: d.spoznMin,
    name: 'Spóźnienie Min'
  },
  {
    fieldId: C.clickup.fields.flagaProblemu,
    value: d.czySpozn ? 'Spóźnienie' : 'Brak problemów',
    name: 'Flaga Problemu'
  },
  {
    fieldId: C.clickup.fields.etapAktualny,
    value: 'Zameldowana',
    name: 'Etap Aktualny'
  }
];

// Filtruj tylko te co nie mają PLACEHOLDER
const validUpdates = updates.filter(u => !u.fieldId.startsWith('PLACEHOLDER'));

return validUpdates.map(u => ({
  json: {
    taskId: d.taskId,
    taskUrl: d.taskUrl,
    fieldId: u.fieldId,
    fieldName: u.name,
    value: u.value,
    // Przekaż dane dalej
    imie: d.imie,
    email: d.email,
    zespol: d.zespol,
    godzina: d.godzina,
    spoznMin: d.spoznMin,
    czySpozn: d.czySpozn,
    stanPoczatkowy: d.stanPoczatkowy,
    dataStr: d.dataStr,
    CONFIG: d.CONFIG,
    mgrEmail: d.mgrEmail,
    zarzadEmail: d.zarzadEmail,
    sysEmail: d.sysEmail
  }
}));

