const now = new Date();
const nowMin = now.getHours() * 60 + now.getMinutes();
const startMin = 8 * 60;
const minPoStart = nowMin - startMin;

return [{
  json: {
    listId: '901522609104',
    listRaporty: '901522609109',
    listAlerty: '901522609082',
    token: 'pk_284536279_ARCLCZPXOG0PMONQ5IBNKY5UJDI4HJRE',
    nowMin,
    minPoStart,
    startMin,
    rapPolMin: 13 * 60,
    rapKonMin: 17 * 60,
    progNiskiStan: 30,
    progSpoznMin: 15,
    progSpoznZarzad: 3,
    zarzadEmail: 'autoleady@gmail.com',
    mgrEmail: 'testautoleady@gmail.com',
    sysEmail: 'testautoleady@gmail.com',
    dataStr: now.toLocaleDateString('pl-PL'),
    timeStr: now.toLocaleTimeString('pl-PL', {hour:'2-digit', minute:'2-digit'}),
    now: now.toISOString()
  }
}];

const cfg = $('SETUP - Konfiguracja').item.json;
const { nowMin, startMin, minPoStart, rapPolMin, progNiskiStan, progSpoznMin } = cfg;

let tasks = [];
const firstJson = $input.first().json;

if (firstJson.tasks && Array.isArray(firstJson.tasks)) {
  tasks = firstJson.tasks;
} else if (Array.isArray(firstJson)) {
  tasks = firstJson;
} else {
  tasks = $input.all().map(item => item.json);
}

tasks = tasks.filter(t => t.id && t.custom_fields);

const alerty = [];
const stats = {
  lacznie: tasks.length,
  obecni: 0,
  spoznieni: 0,
  nieobecni: 0,
  bezRapPol: 0,
  niskaIlosc: 0,
  wymagaUwagi: 0
};

// ============================================
// MECHANIZM DEDUPLIKACJI
// Sprawdź kiedy ostatnio wysłano alert dla danego taska+typu
// Używamy custom field "Uwagi Managera" lub date_updated jako proxy
// GŁÓWNA LOGIKA: alert tego samego typu dla tego samego taska
// wysyłamy max raz na X minut
// ============================================
const COOLDOWN_SPOZNIENIE   = 240; // min - spóźnienie: raz na 4h (już wiemy, nie spam)
const COOLDOWN_NIEOBECNOSC  = 60;  // min - nieobecność: co godzinę
const COOLDOWN_BRAK_RAP_POL = 30;  // min - brak raportu pol: co 30 min
const COOLDOWN_NISKI_STAN   = 60;  // min - niski stan: co godzinę

// Klucz: taskId_typ → timestamp ostatniego alertu
// Przechowujemy w custom field "date_updated" taska jako proxy
// LUB sprawdzamy przez pole tekstowe w tasku
// 
// Najprostsze rozwiązanie: sprawdź date_updated taska
// Jeśli task był update'owany niedawno przez system = alert już wysłano

function minutySinceMs(ms) {
  const now = Date.now();
  return Math.floor((now - parseInt(ms)) / 60000);
}

tasks.forEach(task => {
  const cf = {};
  (task.custom_fields || []).forEach(f => {
    if (f.value !== undefined && f.value !== null) {
      cf[f.name] = f.value;
    }
  });

  const imie    = task.name.trim();
  const taskId  = task.id;
  const taskUrl = task.url;
  const email   = cf['Email'] || cfg.mgrEmail;

  const gPrzyjscia  = cf['Godzina Przyjścia'] || cf['Godzina Przyjscia'] || null;
  const stan13      = parseInt(cf['Stan o 13:00']    || '0') || 0;
  const stanPocz    = parseInt(cf['Stan Początkowy'] || cf['Stan Poczatkowy'] || '0') || 0;
  const rapPol      = cf['Raport Połówkowy'] || cf['Raport Polowkowy'] || null;
  const liczbaSpozn = parseInt(cf['Liczba Spóźnień (łącznie)'] || '0') || 0;
  const status      = (task.status?.status || '').toLowerCase();

  // ---- Minuty od ostatniej aktualizacji taska ----
  const minutesSinceUpdate = minutySinceMs(task.date_updated || task.date_created || 0);

  if (status === 'wymaga uwagi') stats.wymagaUwagi++;

  // ---- OBECNOŚĆ I SPÓŹNIENIE ----
  if (gPrzyjscia && gPrzyjscia.trim() !== '') {
    stats.obecni++;

    const parts = gPrzyjscia.split(':');
    if (parts.length === 2) {
      const hP        = parseInt(parts[0]) || 0;
      const mP        = parseInt(parts[1]) || 0;
      const przyjMin  = hP * 60 + mP;
      const spoznMinut = przyjMin - startMin;

      if (spoznMinut > progSpoznMin) {
        stats.spoznieni++;

        // DEDUPLIKACJA SPÓŹNIENIA:
        // Wyślij alert spóźnienia TYLKO jeśli:
        // - to pierwsza rejestracja (liczbaSpozn zmiana) - task był update'owany < 30 min temu
        // - LUB minęło więcej niż COOLDOWN od ostatniego alertu
        // 
        // Heurystyka: jeśli task był zaktualizowany < 20 min temu
        // = właśnie się zarejestrowała = wyślij alert (pierwsze spóźnienie tego dnia)
        // Jeśli update był dawno = już wiemy o tym spóźnieniu = nie wysyłaj ponownie

        const czyNoweSpoznienie = minutesSinceUpdate < 20;
        const czyPoKooldownie   = minutesSinceUpdate > COOLDOWN_SPOZNIENIE;

        if (czyNoweSpoznienie || czyPoKooldownie) {
          alerty.push({
            typ:          'spoznienie',
            ikona:        '⚠️',
            taskId,
            taskUrl,
            imie,
            email,
            info:         `Spóźnienie ${spoznMinut} min (łącznie: ${liczbaSpozn + 1}x)`,
            pilne:        liczbaSpozn >= cfg.progSpoznZarzad,
            spoznMin:     spoznMinut,
            liczbaSpozn,
            czyNowe:      czyNoweSpoznienie
          });
        }
        // else: znamy to spóźnienie, nie spamujemy
      }
    }
  } else if (minPoStart > 30) {
    stats.nieobecni++;

    // DEDUPLIKACJA NIEOBECNOŚCI:
    // Wyślij alert co COOLDOWN_NIEOBECNOSC minut
    // Sprawdź przez minutesSinceUpdate:
    // Pierwsze wykrycie: task nie był update'owany = minutesSinceUpdate duże = wyślij
    // Kolejne: nie aktualizujemy taska przy braku osoby = zawsze duże = PROBLEM
    //
    // Rozwiązanie: użyj nowMin jako "okna"
    // Wysyłaj alert nieobecności tylko co pełną godzinę (np. 9:00, 10:00...)
    // lub przy pierwszym wykryciu (minPoStart == 31-45)

    const czyPierwszeWykrycie = minPoStart >= 30 && minPoStart <= 45;
    const czyCykliczne        = nowMin % 60 < 15; // pierwsze 15 min każdej godziny

    if (czyPierwszeWykrycie || czyCykliczne) {
      alerty.push({
        typ:    'nieobecnosc',
        ikona:  '❌',
        taskId,
        taskUrl,
        imie,
        email,
        info:   `Nieobecna ${minPoStart} min po starcie`,
        pilne:  minPoStart > 60
      });
    }
  }

  // ---- BRAK RAPORTU POŁÓWKOWEGO ----
  const rapPolOddany = cf['Raport Połówkowy Oddany'] === true
    || cf['Raport Połówkowy Oddany'] === 'true'
    || cf['Raport Polowkowy Oddany'] === true
    || !!rapPol;

  if (nowMin > rapPolMin + 30 && !rapPolOddany && gPrzyjscia) {
    stats.bezRapPol++;

    // DEDUPLIKACJA BRAK RAPORTU POŁ:
    // Wysyłaj tylko:
    // - raz zaraz po 13:30 (nowMin w oknie 810-825)
    // - raz po 14:00 (nowMin w oknie 840-855) jeśli dalej brak
    // - raz po 14:30 jako ostatnie przypomnienie

    const okno1 = nowMin >= rapPolMin + 30  && nowMin < rapPolMin + 45;  // 13:30-13:45
    const okno2 = nowMin >= rapPolMin + 60  && nowMin < rapPolMin + 75;  // 14:00-14:15
    const okno3 = nowMin >= rapPolMin + 90  && nowMin < rapPolMin + 105; // 14:30-14:45

    if (okno1 || okno2 || okno3) {
      alerty.push({
        typ:      'brak_raportu_pol',
        ikona:    '📋',
        taskId,
        taskUrl,
        imie,
        email,
        info:     `Brak raportu połówkowego (po ${okno1 ? '13:30' : okno2 ? '14:00' : '14:30'})`,
        pilne:    nowMin > rapPolMin + 60,
        oknoAlertu: okno1 ? 1 : okno2 ? 2 : 3
      });
    }
  }

  // ---- NISKI STAN ----
  const stanAktualny = stan13 > 0 ? stan13 : stanPocz;
  if (stanAktualny > 0 && stanAktualny < progNiskiStan && gPrzyjscia) {
    stats.niskaIlosc++;

    // DEDUPLIKACJA NISKI STAN:
    // Task był update'owany gdy wpisano niski stan
    // Jeśli minutesSinceUpdate < 30 = świeże = wyślij
    // Jeśli minutesSinceUpdate > COOLDOWN = przypomnij (ale rzadko)

    const czySwiezyAlert  = minutesSinceUpdate < 30;
    const czyPoKooldownie = minutesSinceUpdate > COOLDOWN_NISKI_STAN;

    if (czySwiezyAlert || czyPoKooldownie) {
      alerty.push({
        typ:    'niski_stan',
        ikona:  '🔴',
        taskId,
        taskUrl,
        imie,
        email,
        info:   `Niski stan produktu: ${stanAktualny} szt. (próg: ${progNiskiStan})`,
        pilne:  true
      });
    }
  }
});

const maAlerty = alerty.length > 0;
const maPilne  = alerty.some(a => a.pilne);

return [{
  json: {
    ...cfg,
    alerty,
    stats,
    maAlerty,
    maPilne,
    liczbaAlertow: alerty.length,
    _debug: {
      tasksZnalezione: tasks.length,
      inputFormat: Array.isArray(firstJson) ? 'array' : (firstJson.tasks ? 'tasks_object' : 'items')
    }
  }
}];

const d = $input.first().json;

const kolorMap = {
  spoznienie: '#fff3cd',
  nieobecnosc: '#f8d7da',
  brak_raportu_pol: '#d1ecf1',
  niski_stan: '#f8d7da'
};

const listaHTML = d.alerty.map(a => {
  const kolor = kolorMap[a.typ] || '#f8f9fa';
  const border = a.pilne ? '#dc3545' : '#ffc107';
  return `
  <div style="background:${kolor};padding:12px;border-radius:6px;margin:8px 0;border-left:4px solid ${border};">
    <strong>${a.ikona} ${a.imie}</strong>
    ${a.pilne ? '<span style="color:red;font-weight:bold;"> 🚨 PILNE</span>' : ''}
    <br>
    <span style="color:#555;font-size:13px;">${a.info}</span>
    <br>
    <a href="${a.taskUrl}" style="font-size:12px;color:#667eea;">→ Zobacz task w ClickUp</a>
  </div>`;
}).join('');

const html = `<!DOCTYPE html>
<html>
<body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;">
<div style="background:#e74c3c;color:white;padding:20px;border-radius:10px 10px 0 0;">
  <h2 style="margin:0;">🔔 Alert Systemu - ${d.timeStr}</h2>
  <p style="opacity:0.85;margin:5px 0 0;">Hostessy | ${d.dataStr}</p>
</div>
<div style="background:white;padding:20px;border:1px solid #eee;">
  <div style="display:flex;gap:10px;margin-bottom:15px;flex-wrap:wrap;">
    <div style="background:#e8f5e9;padding:10px 15px;border-radius:8px;text-align:center;flex:1;">
      <b style="font-size:22px;color:green;">${d.stats.obecni}</b><br><small>Obecni</small>
    </div>
    <div style="background:#fce4ec;padding:10px 15px;border-radius:8px;text-align:center;flex:1;">
      <b style="font-size:22px;color:red;">${d.stats.nieobecni}</b><br><small>Nieobecni</small>
    </div>
    <div style="background:#fff3e0;padding:10px 15px;border-radius:8px;text-align:center;flex:1;">
      <b style="font-size:22px;color:orange;">${d.stats.spoznieni}</b><br><small>Spóźnieni</small>
    </div>
    <div style="background:#fce4ec;padding:10px 15px;border-radius:8px;text-align:center;flex:1;">
      <b style="font-size:22px;color:red;">${d.liczbaAlertow}</b><br><small>Alertów</small>
    </div>
  </div>
  <h3 style="color:#e74c3c;">⚠️ Lista Problemów (${d.liczbaAlertow})</h3>
  ${listaHTML}
</div>
<div style="background:#f8f9fa;padding:10px;text-align:center;border:1px solid #eee;border-radius:0 0 10px 10px;">
  <small style="color:#888;">Automatyczny monitoring co 15 min | ${d.timeStr}</small>
</div>
</body>
</html>`;

return [{
  json: {
    ...d,
    emailHTML: html,
    emailSubject: `🔔 Alert Hostessy | ${d.liczbaAlertow} problemów | ${d.timeStr} | ${d.maPilne ? '🚨 PILNE' : ''}`
  }
}];

const now = new Date();
return [{
  json: {
    typRaportu: 'polowkowy',
    tytul: '☀️ Czas na Raport Połówkowy!',
    deadline: '13:30',
    webhookUrl: 'https://TWOJ-N8N.app/webhook/raport-polowkowy',
    listId: '901522609104',
    statusFiltr: ['ETAP 1-2', 'ETAP 3-4'],
    sprawdzPole: 'Raport Połówkowy Oddany',
    dataStr: now.toLocaleDateString('pl-PL'),
    timeStr: '13:00',
    zarzadEmail: 'autoleads@gmail.com',
    mgrEmail: 'testautoleads@gmail.com',
    sysEmail: 'testautoleads@gmail.com',
    now: now.toISOString()
  }
}];

const now = new Date();
return [{
  json: {
    typRaportu: 'koncowy',
    tytul: '🌆 Czas na Raport Końcowy!',
    deadline: '17:00',
