    now: now.toISOString()
  }
}];

const cfg = $('SETUP - Typ Sprawdzenia').item.json;
const tasks = $input.first().json.tasks || [];
const typ = cfg.typSprawdzenia;

const obecni = [];
const bezRaportu = [];
const zRaportem = [];
const nieobecni = [];

tasks.forEach(task => {
  const cf = {};
  (task.custom_fields || []).forEach(f => { cf[f.name] = f.value; });

  const imie = task.name.split(' | ')[0];
  const email = cf['Email Pracownika'] || cfg.mgrEmail;
  const gPrzyjscia = cf['Godzina Przyjścia'] || cf['Godzina Przyjscia'];

  // Sprawdź odpowiedni raport
  let rapOddany;
  let rapTresc;

  if (typ === 'polowkowy') {
    rapOddany = cf['Raport Połówkowy Oddany'] === true ||
                cf['Raport Polowkowy Oddany'] === true;
    rapTresc = cf['Raport Połówkowy'] || cf['Raport Polowkowy'] || '';
  } else {
    rapOddany = cf['Raport Końcowy Oddany'] === true ||
                cf['Raport Koncowy Oddany'] === true;
    rapTresc = cf['Raport Końcowy'] || cf['Raport Koncowy'] || '';
  }

  if (!gPrzyjscia) {
    nieobecni.push(imie);
    return;
  }

  obecni.push({ imie, email, taskId: task.id, taskUrl: task.url });

  if (rapOddany || rapTresc) {
    zRaportem.push(imie);
  } else {
    bezRaportu.push({
      imie,
      email,
      taskId: task.id,
      taskUrl: task.url,
      gPrzyjscia
    });
  }
});

const procent = obecni.length > 0
  ? Math.round((zRaportem.length / obecni.length) * 100)
  : 0;

const maProblemy = bezRaportu.length > 0;
const krytyczne = bezRaportu.length > (obecni.length * 0.3); // >30% bez raportu

return [{
  json: {
    ...cfg,
    obecni: obecni.length,
    nieobecni: nieobecni.length,
    zRaportem: zRaportem.length,
    bezRaportu,
    liczbaBezRaportu: bezRaportu.length,
    procent,
    maProblemy,
    krytyczne,
    zRaportNazwy: zRaportem,
    nieobecniNazwy: nieobecni
  }
}];

// Wyślij indywidualne przypomnienia do osób bez raportu
